// === SENSOR SIMULATOR ===
// Node-RED Function node
// Output: [ [msg1, msg2, msg3] ]

const machines = {
    Hopper_01: {
        type: "Hopper",
        base: { temp: 25.5, vib: 1.1, curr: 6.8, weight: 430 },
        normal:  { temp: [24.0, 28.0], vib: [0.9, 1.8], curr: [6.0, 8.0], weight: [380, 500] },
        warning: { temp: [28.0, 55.0], vib: [2.0, 4.5], curr: [7.5, 12.0], weight: [50, 350] },
        critical:{ temp: [45.0, 90.0], vib: [3.5, 7.0], curr: [10.0, 16.0], weight: [0, 50] }
    },
    Conveyor_01: {
        type: "Conveyor",
        base: { temp: 25.2, vib: 0.9, curr: 5.2, weight: 18 },
        normal:  { temp: [24.0, 27.0], vib: [0.7, 1.5], curr: [4.8, 6.2], weight: [0, 40] },
        warning: { temp: [27.0, 45.0], vib: [2.0, 3.8], curr: [7.0, 10.5], weight: [0, 20] },
        critical:{ temp: [40.0, 80.0], vib: [3.5, 6.5], curr: [10.0, 15.0], weight: [0, 5] }
    },
    Mixer_01: {
        type: "Mixer",
        base: { temp: 28.5, vib: 1.9, curr: 6.5, weight: 140 },
        normal:  { temp: [27.0, 32.0], vib: [1.5, 2.5], curr: [6.0, 7.6], weight: [100, 220] },
        warning: { temp: [32.0, 60.0], vib: [2.5, 4.5], curr: [8.0, 12.0], weight: [200, 360] },
        critical:{ temp: [45.0, 95.0], vib: [3.5, 7.5], curr: [10.5, 17.0], weight: [300, 500] }
    }
};

function clamp(v, min, max) {
    return Math.max(min, Math.min(max, v));
}

function rand(min, max) {
    return min + Math.random() * (max - min);
}

function rint(min, max) {
    return Math.floor(rand(min, max + 1));
}

function evolve(current, target, drift, noise, min, max) {
    current += (target - current) * drift;
    current += rand(-noise, noise);
    return clamp(current, min, max);
}

let state = context.get("state") || {};
let tick = (context.get("tick") || 0) + 1;
const now = new Date().toISOString();
const out = [];

for (const [id, def] of Object.entries(machines)) {
    if (!state[id]) {
        state[id] = {
            temp: def.base.temp + rand(-0.4, 0.4),
            vib: def.base.vib + rand(-0.1, 0.1),
            curr: def.base.curr + rand(-0.2, 0.2),
            weight: def.base.weight + rand(-5, 5),
            mode: "RUNNING",
            modeRemaining: rint(16, 26)
        };
    }

    const s = state[id];

    // lifecycle
    if (s.modeRemaining <= 0) {
        if (s.mode === "RUNNING") {
            s.mode = "WARNING";
            s.modeRemaining = rint(4, 8);
        } else if (s.mode === "WARNING") {
            if (Math.random() < 0.35) {
                s.mode = "CRITICAL";
                s.modeRemaining = rint(2, 4);
            } else {
                s.mode = "RUNNING";
                s.modeRemaining = rint(10, 20);
            }
        } else if (s.mode === "CRITICAL") {
            s.mode = "RUNNING";
            s.modeRemaining = rint(20, 35);
            s.temp = def.base.temp + rand(-0.5, 0.5);
            s.vib = def.base.vib + rand(-0.1, 0.1);
            s.curr = def.base.curr + rand(-0.2, 0.2);
        }
    }

    s.modeRemaining -= 1;

    const key = s.mode === "RUNNING" ? "normal" : s.mode.toLowerCase();
    const b = def[key];

    s.temp = evolve(s.temp, rand(b.temp[0], b.temp[1]), 0.15, 0.45, 18, 100);
    s.vib = evolve(s.vib, rand(b.vib[0], b.vib[1]), 0.20, 0.20, 0, 10);
    s.curr = evolve(s.curr, rand(b.curr[0], b.curr[1]), 0.18, 0.25, 0, 25);
    s.weight = evolve(s.weight, rand(b.weight[0], b.weight[1]), 0.14, 2.5, 0, 600);

    // light isolated noise so it does not look like a sterile spreadsheet
    if (Math.random() < 0.08) {
        s.vib += rand(0.1, 0.4);
    }

    const level = id === "Hopper_01"
        ? clamp((s.weight / 500) * 100, 0, 100)
        : 0;

    out.push({
        payload: {
            timestamp: now,
            machine_id: id,
            machine_type: def.type,
            tick,
            sensors: {
                temperature: +s.temp.toFixed(2),
                vibration: +s.vib.toFixed(2),
                current_amp: +s.curr.toFixed(2),
                weight_kg: +s.weight.toFixed(2),
                level_percent: +level.toFixed(2)
            },
            status: s.mode,
            mode_remaining: s.modeRemaining
        }
    });

    state[id] = s;
}

context.set("state", state);
context.set("tick", tick);

return [out];

// === DECISION LOGIC ===
// Node-RED Function node
// Input: msg.payload from simulator
// Output: msg.payload with status + anomaly_score + decision_reason

const p = msg.payload || {};
const s = p.sensors || {};
const id = p.machine_id || "UNKNOWN";

function n(v) {
    const x = Number(v);
    return Number.isFinite(x) ? x : null;
}

const temp = n(s.temperature);
const vib = n(s.vibration);
const curr = n(s.current_amp);
const weight = n(s.weight_kg);
const level = n(s.level_percent);

if ([temp, vib, curr, weight, level].some(v => v === null)) {
    msg.payload = {
        ...p,
        status: "SENSOR_ERROR",
        anomaly_score: 100,
        decision_reason: ["Invalid sensor data"]
    };
    return msg;
}

let score = 0;
let reasons = [];

// continuous scoring
if (vib > 1.5) {
    const v = (vib - 1.5) * 2.2;
    score += v;
    reasons.push(`Vibration elevated (+${v.toFixed(2)})`);
}

if (curr > 6.5) {
    const c = (curr - 6.5) * 1.8;
    score += c;
    reasons.push(`Current above baseline (+${c.toFixed(2)})`);
}

if (temp > 35) {
    const t = (temp - 35) * 0.15;
    score += t;
    reasons.push(`Temperature rising (+${t.toFixed(2)})`);
}

// machine-specific rules
if (id === "Mixer_01") {
    if (vib > 2.8 && curr > 9) {
        score += 3;
        reasons.push("Mixer mechanical stress");
    }
}

if (id === "Conveyor_01") {
    if (weight === 0 && vib > 2.5 && curr > 8) {
        score += 3;
        reasons.push("Dry-run risk");
    }
}

if (id === "Hopper_01") {
    if (level > 95) {
        score += 2;
        reasons.push("Hopper near overflow");
    }
    if (level < 5) {
        score += 2;
        reasons.push("Hopper near empty");
    }
}

// status thresholds
let status = "RUNNING";

if (score >= 6) {
    status = "CRITICAL";
} else if (score >= 2.5) {
    status = "WARNING";
} else if (score > 0) {
    status = "WATCH";
}

msg.payload = {
    ...p,
    status,
    anomaly_score: +score.toFixed(2),
    decision_reason: reasons.length ? reasons : ["No anomalies detected"]
};

return msg;
